/**
 * CC4102 - Diseño y Análisis de Algoritmos
 * Tarea 2: Algoritmo de Kruskal
 *
 * Implementación de 4 variaciones del algoritmo de Kruskal:
 *   1) Kruskal con optimización de find (path compression) + arreglo ordenado
 *   2) Kruskal con optimización de find (path compression) + heap
 *   3) Kruskal sin optimización de find + arreglo ordenado
 *   4) Kruskal sin optimización de find + heap
 *
 * Además se ejecutan experimentos variando N desde 2^5 hasta 2^12,
 * midiendo tiempos de ejecución promedio sobre 5 repeticiones.
 */

#include <iostream>
#include <vector>
#include <algorithm>
#include <queue>
#include <chrono>
#include <random>
#include <cmath>
#include <iomanip>
#include <fstream>
#include <string>
#include <cassert>

using namespace std;

/* ==================================================================
 *  ESTRUCTURAS DE DATOS: Nodo y Arista
 * ================================================================== */

/**
 * Estructura que representa un nodo en el plano bidimensional.
 * Cada nodo tiene coordenadas (x, y) reales de 64 bits en [0, 1].
 */
struct Node {
    double x, y;  ///< Coordenadas del nodo

    /** Constructor por defecto. */
    Node() : x(0), y(0) {}

    /** Constructor con coordenadas. */
    Node(double x, double y) : x(x), y(y) {}
};

/**
 * Estructura que representa una arista del grafo.
 * Almacena punteros a los nodos que conecta y el peso de la arista.
 * El peso es el cuadrado de la distancia euclidiana entre los nodos.
 */
struct Edge {
    Node* u;        ///< Puntero al primer nodo
    Node* v;        ///< Puntero al segundo nodo
    double weight;  ///< Peso de la arista (cuadrado de distancia euclidiana)

    /** Constructor. */
    Edge(Node* u, Node* v) : u(u), v(v) {
        double dx = u->x - v->x;
        double dy = u->y - v->y;
        weight = dx * dx + dy * dy;
    }

    /** Operador de comparación para ordenar aristas por peso (menor primero). */
    bool operator<(const Edge& other) const {
        return weight < other.weight;
    }
};

/* ==================================================================
 *  INTERFAZ UNION-FIND
 * ================================================================== */

/**
 * Clase Union-Find (Conjuntos Disjuntos).
 * Mantiene un arreglo de padres y tamaños para cada nodo.
 * Soporta dos modos de find: con y sin optimización de path compression.
 */
class UnionFind {
private:
    int n;               ///< Cantidad de nodos
    vector<int> parent;  ///< Arreglo de padres: parent[i] es el padre del nodo i
    vector<int> size;    ///< Arreglo de tamaños: size[i] es el tamaño del árbol con raíz i

public:
    /**
     * Constructor: inicializa n nodos, cada uno como su propia raíz.
     * @param n Cantidad de nodos.
     */
    UnionFind(int n) : n(n), parent(n), size(n, 1) {
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }

    /**
     * find sin optimización (sin path compression).
     * Busca la raíz del árbol que contiene al nodo i subiendo por los padres.
     * @param i Índice del nodo.
     * @return Índice de la raíz del árbol.
     */
    int findNoOptimize(int i) {
        while (parent[i] != i) {
            i = parent[i];
        }
        return i;
    }

    /**
     * find con optimización (path compression).
     * Busca la raíz del árbol que contiene al nodo i y comprime el camino,
     * haciendo que todos los nodos visitados apunten directamente a la raíz.
     * @param i Índice del nodo.
     * @return Índice de la raíz del árbol.
     */
    int findOptimize(int i) {
        if (parent[i] != i) {
            parent[i] = findOptimize(parent[i]);
        }
        return parent[i];
    }

    /**
     * Union de dos árboles por tamaño.
     * La raíz del árbol más pequeño queda como hijo de la raíz del árbol más grande.
     * @param a Raíz del primer árbol.
     * @param b Raíz del segundo árbol.
     */
    void unionSets(int a, int b) {
        // a y b deben ser raíces
        if (size[a] < size[b]) {
            parent[a] = b;
            size[b] += size[a];
        } else {
            parent[b] = a;
            size[a] += size[b];
        }
    }

    /**
     * Reinicia la estructura al estado inicial.
     */
    void reset() {
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            size[i] = 1;
        }
    }
};

/* ==================================================================
 *  ALGORITMO DE KRUSKAL (4 VARIACIONES)
 * ================================================================== */

/**
 * Calcula el MST usando Kruskal con arreglo ordenado y find optimizado.
 *
 * @param edges Vector de aristas (se ordena internamente).
 * @param uf    Estructura Union-Find inicializada.
 * @param n     Cantidad de nodos.
 * @return Vector de aristas que forman el árbol cobertor mínimo.
 */
vector<Edge> kruskalSortedOptimized(vector<Edge>& edges, UnionFind& uf, int n) {
    // Ordenar aristas por peso (O(m log m))
    sort(edges.begin(), edges.end());

    vector<Edge> mst;
    mst.reserve(n - 1);

    for (const Edge& e : edges) {
        int ru = uf.findOptimize(e.u - nullptr);  // find optimizado
        int rv = uf.findOptimize(e.v - nullptr);

        if (ru != rv) {
            mst.push_back(e);
            uf.unionSets(ru, rv);
            if ((int)mst.size() == n - 1) break;
        }
    }
    return mst;
}

/**
 * Calcula el MST usando Kruskal con arreglo ordenado y find sin optimizar.
 *
 * @param edges Vector de aristas (se ordena internamente).
 * @param uf    Estructura Union-Find inicializada.
 * @param n     Cantidad de nodos.
 * @return Vector de aristas que forman el árbol cobertor mínimo.
 */
vector<Edge> kruskalSortedNoOptimize(vector<Edge>& edges, UnionFind& uf, int n) {
    sort(edges.begin(), edges.end());

    vector<Edge> mst;
    mst.reserve(n - 1);

    for (const Edge& e : edges) {
        int ru = uf.findNoOptimize(e.u - nullptr);  // find sin optimizar
        int rv = uf.findNoOptimize(e.v - nullptr);

        if (ru != rv) {
            mst.push_back(e);
            uf.unionSets(ru, rv);
            if ((int)mst.size() == n - 1) break;
        }
    }
    return mst;
}

/**
 * Calcula el MST usando Kruskal con heap y find optimizado.
 *
 * @param edges Vector de aristas (se heapifica internamente).
 * @param uf    Estructura Union-Find inicializada.
 * @param n     Cantidad de nodos.
 * @return Vector de aristas que forman el árbol cobertor mínimo.
 */
vector<Edge> kruskalHeapOptimized(vector<Edge>& edges, UnionFind& uf, int n) {
    // Construir heap (min-heap) con las aristas
    priority_queue<Edge, vector<Edge>, greater<Edge>> pq;
    for (const Edge& e : edges) {
        pq.push(e);
    }

    vector<Edge> mst;
    mst.reserve(n - 1);

    while (!pq.empty() && (int)mst.size() < n - 1) {
        Edge e = pq.top();
        pq.pop();

        int ru = uf.findOptimize(e.u - nullptr);  // find optimizado
        int rv = uf.findOptimize(e.v - nullptr);

        if (ru != rv) {
            mst.push_back(e);
            uf.unionSets(ru, rv);
        }
    }
    return mst;
}

/**
 * Calcula el MST usando Kruskal con heap y find sin optimizar.
 *
 * @param edges Vector de aristas (se heapifica internamente).
 * @param uf    Estructura Union-Find inicializada.
 * @param n     Cantidad de nodos.
 * @return Vector de aristas que forman el árbol cobertor mínimo.
 */
vector<Edge> kruskalHeapNoOptimize(vector<Edge>& edges, UnionFind& uf, int n) {
    priority_queue<Edge, vector<Edge>, greater<Edge>> pq;
    for (const Edge& e : edges) {
        pq.push(e);
    }

    vector<Edge> mst;
    mst.reserve(n - 1);

    while (!pq.empty() && (int)mst.size() < n - 1) {
        Edge e = pq.top();
        pq.pop();

        int ru = uf.findNoOptimize(e.u - nullptr);  // find sin optimizar
        int rv = uf.findNoOptimize(e.v - nullptr);

        if (ru != rv) {
            mst.push_back(e);
            uf.unionSets(ru, rv);
        }
    }
    return mst;
}

/* ==================================================================
 *  GENERACIÓN DE DATOS DE ENTRADA
 * ================================================================== */

/**
 * Genera N puntos aleatorios en el plano [0, 1] x [0, 1].
 * Los puntos se almacenan en el vector nodes y se retorna
 * un vector con todas las aristas posibles entre ellos.
 *
 * @param nodes   Vector donde se almacenarán los nodos generados.
 * @param n       Cantidad de nodos a generar.
 * @param rng     Generador de números aleatorios (ya inicializado).
 * @return Vector con todas las aristas (N*(N-1)/2 aristas).
 */
vector<Edge> generateRandomGraph(vector<Node>& nodes, int n, mt19937_64& rng) {
    uniform_real_distribution<double> dist(0.0, 1.0);

    nodes.clear();
    nodes.reserve(n);
    for (int i = 0; i < n; i++) {
        nodes.emplace_back(dist(rng), dist(rng));
    }

    vector<Edge> edges;
    edges.reserve(n * (n - 1) / 2);
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            edges.emplace_back(&nodes[i], &nodes[j]);
        }
    }
    return edges;
}

/* ==================================================================
 *  FUNCIÓN PRINCIPAL Y EXPERIMENTOS
 * ================================================================== */

/**
 * Ejecuta los experimentos de la tarea:
 * Para N ∈ {2^5, 2^6, ..., 2^12}:
 *   - Genera 5 secuencias de N puntos aleatorios.
 *   - Para cada secuencia, ejecuta las 4 variaciones de Kruskal y mide tiempo.
 *   - Calcula el promedio de los 5 tiempos para cada variación.
 * Imprime resultados en consola y los guarda en un archivo CSV.
 */
int main() {
    cout << fixed << setprecision(6);
    cout << "=== Tarea 2: Algoritmo de Kruskal ===" << endl;
    cout << "Ejecutando experimentos..." << endl << endl;

    // Semilla para reproducibilidad
    mt19937_64 rng(12345);

    // Tamaños de entrada: 2^5 a 2^12
    vector<int> sizes;
    for (int exp = 5; exp <= 12; exp++) {
        sizes.push_back(1 << exp);
    }

    // Resultados: [variacion][size_idx] = vector de 5 tiempos
    // 0: sorted+opt, 1: sorted+noopt, 2: heap+opt, 3: heap+noopt
    vector<vector<vector<double>>> allTimes(4, vector<vector<double>>(sizes.size()));

    cout << "N";
    for (int v = 0; v < 4; v++) {
        cout << "," << nameVariation(v);
    }
    // Print header for CSV
    // ...

    for (size_t si = 0; si < sizes.size(); si++) {
        int n = sizes[si];
        cout << "Procesando N = " << n << " (" << (si+1) << "/" << sizes.size() << ")" << endl;

        // 5 repeticiones
        for (int rep = 0; rep < 5; rep++) {
            // Generar grafo aleatorio
            vector<Node> nodes;
            vector<Edge> edges = generateRandomGraph(nodes, n, rng);

            // Para cada variación, medir tiempo
            // Variación 0: Sorted + Optimized
            {
                UnionFind uf(n);
                vector<Edge> edgesCopy = edges;  // copia para no reordenar

                auto start = chrono::high_resolution_clock::now();
                vector<Edge> mst = kruskalSortedOptimized(edgesCopy, uf, n);
                auto end = chrono::high_resolution_clock::now();

                double elapsed = chrono::duration<double>(end - start).count();
                allTimes[0][si].push_back(elapsed);
            }

            // Variación 1: Sorted + No Optimize
            {
                UnionFind uf(n);
                vector<Edge> edgesCopy = edges;

                auto start = chrono::high_resolution_clock::now();
                vector<Edge> mst = kruskalSortedNoOptimize(edgesCopy, uf, n);
                auto end = chrono::high_resolution_clock::now();

                double elapsed = chrono::duration<double>(end - start).count();
                allTimes[1][si].push_back(elapsed);
            }

            // Variación 2: Heap + Optimized
            {
                UnionFind uf(n);
                vector<Edge> edgesCopy = edges;

                auto start = chrono::high_resolution_clock::now();
                vector<Edge> mst = kruskalHeapOptimized(edgesCopy, uf, n);
                auto end = chrono::high_resolution_clock::now();

                double elapsed = chrono::duration<double>(end - start).count();
                allTimes[2][si].push_back(elapsed);
            }

            // Variación 3: Heap + No Optimize
            {
                UnionFind uf(n);
                vector<Edge> edgesCopy = edges;

                auto start = chrono::high_resolution_clock::now();
                vector<Edge> mst = kruskalHeapNoOptimize(edgesCopy, uf, n);
                auto end = chrono::high_resolution_clock::now();

                double elapsed = chrono::duration<double>(end - start).count();
                allTimes[3][si].push_back(elapsed);
            }
        }
    }

    // Calcular promedios y mostrar resultados
    cout << endl;
    cout << "=== RESULTADOS ===" << endl;
    cout << "Tiempos promedio (en segundos) sobre 5 repeticiones:" << endl << endl;

    // Cabecera
    cout << left << setw(8) << "N";
    cout << setw(22) << "Sorted+Opt";
    cout << setw(22) << "Sorted+NoOpt";
    cout << setw(22) << "Heap+Opt";
    cout << setw(22) << "Heap+NoOpt";
    cout << endl;
    cout << string(90, '-') << endl;

    for (size_t si = 0; si < sizes.size(); si++) {
        int n = sizes[si];
        cout << left << setw(8) << n;

        for (int v = 0; v < 4; v++) {
            double sum = 0;
            for (double t : allTimes[v][si]) {
                sum += t;
            }
            double avg = sum / allTimes[v][si].size();
            cout << setw(22) << avg;
        }
        cout << endl;
    }

    // Guardar resultados en CSV
    ofstream csv("resultados.csv");
    csv << "N,Sorted+Opt,Sorted+NoOpt,Heap+Opt,Heap+NoOpt" << endl;
    for (size_t si = 0; si < sizes.size(); si++) {
        int n = sizes[si];
        csv << n;
        for (int v = 0; v < 4; v++) {
            double sum = 0;
            for (double t : allTimes[v][si]) {
                sum += t;
            }
            double avg = sum / allTimes[v][si].size();
            csv << "," << avg;
        }
        csv << endl;
    }
    csv.close();

    // También guardar datos detallados (cada repetición)
    ofstream csvDet("resultados_detalle.csv");
    csvDet << "N,Repeticion,Sorted+Opt,Sorted+NoOpt,Heap+Opt,Heap+NoOpt" << endl;
    for (size_t si = 0; si < sizes.size(); si++) {
        int n = sizes[si];
        for (int rep = 0; rep < 5; rep++) {
            csvDet << n << "," << (rep + 1);
            for (int v = 0; v < 4; v++) {
                csvDet << "," << allTimes[v][si][rep];
            }
            csvDet << endl;
        }
    }
    csvDet.close();

    cout << endl;
    cout << "Resultados guardados en 'resultados.csv' y 'resultados_detalle.csv'" << endl;

    return 0;
}

/**
 * CC4102 - Diseño y Análisis de Algoritmos
 * Tarea 2: Algoritmo de Kruskal
 *
 * Implementación de 4 variaciones del algoritmo de Kruskal:
 *   1) Kruskal con optimización de find (path compression) + arreglo ordenado
 *   2) Kruskal con optimización de find (path compression) + heap
 *   3) Kruskal sin optimización de find + arreglo ordenado
 *   4) Kruskal sin optimización de find + heap
 *
 * Además se ejecutan experimentos variando N desde 2^5 hasta 2^12,
 * midiendo tiempos de ejecución promedio sobre 5 repeticiones.
 */

#include <iostream>
#include <vector>
#include <algorithm>
#include <queue>
#include <chrono>
#include <random>
#include <cmath>
#include <iomanip>
#include <fstream>
#include <string>
#include <cassert>

using namespace std;

/* ==================================================================
 *  ESTRUCTURAS DE DATOS: Nodo y Arista
 * ================================================================== */

/**
 * Estructura que representa un nodo en el plano bidimensional.
 * Cada nodo tiene coordenadas (x, y) reales de 64 bits en [0, 1].
 * Ademas, guarda un identificador numerico unico (indice en el arreglo)
 * para poder acceder a la estructura Union-Find.
 */
struct Node {
    double x;      ///< Coordenada x del nodo (en [0, 1])
    double y;      ///< Coordenada y del nodo (en [0, 1])
    int id;        ///< Identificador unico del nodo (indice en el arreglo global)

    /**
     * Constructor con coordenadas e identificador.
     * @param x Coordenada x.
     * @param y Coordenada y.
     * @param id Identificador unico del nodo.
     */
    Node(double x, double y, int id) : x(x), y(y), id(id) {}
};

/**
 * Estructura que representa una arista del grafo.
 * Almacena punteros a los nodos que conecta y el peso de la arista.
 * El peso se calcula como el cuadrado de la distancia euclidiana
 * entre los nodos: d = (x1 - x2)^2 + (y1 - y2)^2.
 */
struct Edge {
    Node* u;        ///< Puntero al primer nodo
    Node* v;        ///< Puntero al segundo nodo
    double weight;  ///< Peso de la arista (cuadrado de distancia euclidiana)

    /**
     * Constructor: calcula automaticamente el peso de la arista.
     * @param u Puntero al primer nodo.
     * @param v Puntero al segundo nodo.
     */
    Edge(Node* u, Node* v) : u(u), v(v) {
        double dx = u->x - v->x;
        double dy = u->y - v->y;
        weight = dx * dx + dy * dy;
    }

    /**
     * Operador menor que, para ordenar aristas por peso ascendente.
     * @param other Otra arista para comparar.
     * @return true si esta arista tiene menor peso que other.
     */
    bool operator<(const Edge& other) const {
        return weight < other.weight;
    }

    /**
     * Operador mayor que, para usar en min-heap via greater<Edge>.
     * @param other Otra arista para comparar.
     * @return true si esta arista tiene mayor peso que other.
     */
    bool operator>(const Edge& other) const {
        return weight > other.weight;
    }
};

/* ==================================================================
 *  INTERFAZ UNION-FIND
 * ================================================================== */

/**
 * Clase Union-Find (Conjuntos Disjuntos) para manejar la deteccion
 * de ciclos en el algoritmo de Kruskal.
 *
 * Inicialmente cada nodo es su propio arbol (raiz de si mismo).
 * Soporta dos modos de operacion para find:
 *   - find sin optimizacion: solo sube por los padres hasta la raiz.
 *   - find con optimizacion (path compression): comprime el camino
 *     haciendo que todos los nodos visitados apunten directamente a la raiz.
 * La union se realiza por tamanio: la raiz del arbol mas pequeno
 * se cuelga de la raiz del arbol mas grande.
 */
class UnionFind {
private:
    int n;               ///< Cantidad total de nodos
    vector<int> parent;  ///< parent[i] = padre del nodo i (si parent[i]==i, es raiz)
    vector<int> sz;      ///< sz[i] = cantidad de nodos en el arbol con raiz i (solo valido si i es raiz)

public:
    /**
     * Constructor: inicializa n nodos, cada uno como su propia raiz.
     * @param n Cantidad de nodos.
     */
    UnionFind(int n) : n(n), parent(n), sz(n, 1) {
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }

    /**
     * Operacion find SIN optimizacion de path compression.
     * Busca la raiz del arbol que contiene al nodo i,
     * subiendo por los padres hasta llegar a la raiz.
     *
     * @param i Identificador del nodo.
     * @return Identificador de la raiz del arbol que contiene a i.
     */
    int findNoOptimize(int i) const {
        while (parent[i] != i) {
            i = parent[i];
        }
        return i;
    }

    /**
     * Operacion find CON optimizacion de path compression.
     * Busca la raiz del arbol que contiene al nodo i,
     * y comprime el camino: todos los nodos visitados
     * quedan apuntando directamente a la raiz.
     *
     * @param i Identificador del nodo.
     * @return Identificador de la raiz del arbol que contiene a i.
     */
    int findOptimize(int i) {
        if (parent[i] != i) {
            parent[i] = findOptimize(parent[i]);
        }
        return parent[i];
    }

    /**
     * Union de dos arboles por tamanio.
     * La raiz del arbol mas pequeno se cuelga de la raiz
     * del arbol mas grande. Si tienen igual tamano, se une
     * el segundo al primero (arbitrario).
     *
     * @param a Identificador de la raiz del primer arbol.
     * @param b Identificador de la raiz del segundo arbol.
     * @pre a y b deben ser raices (find(a)==a, find(b)==b).
     */
    void unionSets(int a, int b) {
        if (sz[a] < sz[b]) {
            parent[a] = b;
            sz[b] += sz[a];
        } else {
            parent[b] = a;
            sz[a] += sz[b];
        }
    }

    /**
     * Reinicia la estructura a su estado inicial.
     * Cada nodo vuelve a ser su propia raiz.
     */
    void reset() {
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            sz[i] = 1;
        }
    }
};

/* ==================================================================
 *  ALGORITMO DE KRUSKAL (4 VARIACIONES)
 * ================================================================== */

/**
 * Kruskal con arreglo ordenado y find optimizado (path compression).
 *
 * Descripcion:
 *   1. Ordena las aristas por peso usando sort() de la STL (O(m log m)).
 *   2. Itera las aristas en orden creciente de peso.
 *   3. Para cada arista, aplica findOptimize() a ambos extremos.
 *   4. Si estan en distintos arboles, une los arboles y agrega la arista al MST.
 *   5. Termina cuando |MST| = n-1.
 *
 * @param edges Vector de aristas del grafo completo. Se ordena internamente.
 * @param uf    Instancia de Union-Find (debe estar inicializada con n nodos).
 * @param n     Cantidad de nodos.
 * @return Vector con las aristas del arbol cobertor minimo.
 */
vector<Edge> kruskalSortedOptimized(vector<Edge>& edges, UnionFind& uf, int n) {
    sort(edges.begin(), edges.end());

    vector<Edge> mst;
    mst.reserve(n - 1);

    for (const Edge& e : edges) {
        int ru = uf.findOptimize(e.u->id);
        int rv = uf.findOptimize(e.v->id);

        if (ru != rv) {
            mst.push_back(e);
            uf.unionSets(ru, rv);
            if ((int)mst.size() == n - 1) break;
        }
    }
    return mst;
}

/**
 * Kruskal con arreglo ordenado y find SIN optimizar.
 *
 * Descripcion:
 *   Identico al anterior, pero usa findNoOptimize() en lugar de findOptimize().
 *
 * @param edges Vector de aristas del grafo completo. Se ordena internamente.
 * @param uf    Instancia de Union-Find.
 * @param n     Cantidad de nodos.
