/**
 * Kruskal con heap (cola de prioridad) y find optimizado (path compression).
 *
 * Descripcion:
 *   1. Construye un min-heap con todas las aristas (O(m)).
 *   2. Extrae la arista de menor peso iterativamente.
 *   3. Para cada arista, aplica findOptimize() a ambos extremos.
 *   4. Si estan en distintos arboles, une los arboles y agrega la arista al MST.
 *   5. Termina cuando |MST| = n-1 o se vacia el heap.
 *
 * @param edges Vector de aristas del grafo completo. Se copian al heap.
 * @param uf    Instancia de Union-Find.
 * @param n     Cantidad de nodos.
 * @return Vector con las aristas del arbol cobertor minimo.
 */
vector<Edge> kruskalHeapOptimized(vector<Edge>& edges, UnionFind& uf, int n) {
    // Construir min-heap usando priority_queue con greater<Edge>
    priority_queue<Edge, vector<Edge>, greater<Edge>> pq;
    for (const Edge& e : edges) {
        pq.push(e);
    }

    vector<Edge> mst;
    mst.reserve(n - 1);

    while (!pq.empty() && (int)mst.size() < n - 1) {
        Edge e = pq.top();
        pq.pop();

        int ru = uf.findOptimize(e.u->id);
        int rv = uf.findOptimize(e.v->id);

        if (ru != rv) {
            mst.push_back(e);
            uf.unionSets(ru, rv);
        }
    }
    return mst;
}

/**
 * Kruskal con heap (cola de prioridad) y find SIN optimizar.
 *
 * Descripcion:
 *   Identico al anterior, pero usa findNoOptimize() en lugar de findOptimize().
 *
 * @param edges Vector de aristas del grafo completo.
 * @param uf    Instancia de Union-Find.
 * @param n     Cantidad de nodos.
 * @return Vector con las aristas del arbol cobertor minimo.
