/**
 * Genera N puntos aleatorios en el plano [0, 1] x [0, 1] y crea
 * todas las aristas posibles entre ellos.
 *
 * Los nodos se almacenan en el vector 'nodes' y cada uno recibe
 * un identificador unico igual a su posicion en el vector.
 * Las aristas se generan como todos los pares (i, j) con i < j,
 * y apuntan a los nodos mediante punteros.
 *
 * @param nodes Vector donde se almacenaran los nodos generados (se limpia al inicio).
 * @param n     Cantidad de nodos a generar.
 * @param rng   Generador de numeros aleatorios (mt19937_64) ya inicializado.
 * @return Vector con todas las aristas del grafo completo (N*(N-1)/2 aristas).
 */
vector<Edge> generateRandomGraph(vector<Node>& nodes, int n, mt19937_64& rng) {
    uniform_real_distribution<double> dist(0.0, 1.0);

    nodes.clear();
    nodes.reserve(n);
    for (int i = 0; i < n; i++) {
        nodes.emplace_back(dist(rng), dist(rng), i);
    }

    vector<Edge> edges;
    edges.reserve(n * (n - 1) / 2);
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            edges.emplace_back(&nodes[i], &nodes[j]);
        }
    }
    return edges;
}

