 * @param v Indice de variacion (0..3).
 * @return String con el nombre de la variacion.
 */
string nameVariation(int v) {
    switch (v) {
        case 0: return "Sorted+Opt";
        case 1: return "Sorted+NoOpt";
        case 2: return "Heap+Opt";
        case 3: return "Heap+NoOpt";
        default: return "Unknown";
    }
}

