 * ================================================================== */

/**
 * Punto de entrada del programa.
 *
 * Ejecuta los experimentos de la tarea:
 *   - Para N ∈ {2^5, 2^6, ..., 2^12}:
 *       - Genera 5 secuencias de N puntos aleatorios.
 *       - Para cada secuencia, ejecuta las 4 variaciones de Kruskal y mide el tiempo.
 *       - Calcula el promedio de los 5 tiempos para cada variacion.
 *   - Imprime los resultados en consola.
 *   - Guarda los resultados en 'resultados.csv' (promedios)
 *     y 'resultados_detalle.csv' (cada repeticion individual).
 *
 * @return 0 si la ejecucion fue exitosa.
 */
int main() {
    cout << fixed << setprecision(6);
    cout << "=== Tarea 2: Algoritmo de Kruskal ===" << endl;
    cout << "Ejecutando experimentos..." << endl << endl;

    // Semilla fija para reproducibilidad de resultados
    mt19937_64 rng(12345);

    // Tamanios de entrada: 2^5 a 2^12
    vector<int> sizes;
    for (int exp = 5; exp <= 12; exp++) {
        sizes.push_back(1 << exp);
    }

    // Resultados: [variacion][size_idx] = vector de 5 tiempos (una por repeticion)
    // variacion 0: Sorted+Opt
    // variacion 1: Sorted+NoOpt
    // variacion 2: Heap+Opt
    // variacion 3: Heap+NoOpt
    vector<vector<vector<double>>> allTimes(4, vector<vector<double>>(sizes.size()));

    for (size_t si = 0; si < sizes.size(); si++) {
        int n = sizes[si];
        cout << "Procesando N = " << n << " (" << (si+1) << "/" << sizes.size() << ")" << endl;

        // 5 repeticiones para cada tamanio
        for (int rep = 0; rep < 5; rep++) {
            // Generar grafo aleatorio con N nodos
            vector<Node> nodes;
            vector<Edge> edges = generateRandomGraph(nodes, n, rng);

            // --- Variacion 0: Sorted + Optimized ---
            {
                UnionFind uf(n);
                vector<Edge> edgesCopy = edges;  // copia para mantener original intacto

                auto start = chrono::high_resolution_clock::now();
                vector<Edge> mst = kruskalSortedOptimized(edgesCopy, uf, n);
                auto end = chrono::high_resolution_clock::now();

                (void)mst; // suprimir warning de variable no usada
                double elapsed = chrono::duration<double>(end - start).count();
                allTimes[0][si].push_back(elapsed);
            }

            // --- Variacion 1: Sorted + No Optimize ---
            {
                UnionFind uf(n);
                vector<Edge> edgesCopy = edges;

                auto start = chrono::high_resolution_clock::now();
                vector<Edge> mst = kruskalSortedNoOptimize(edgesCopy, uf, n);
                auto end = chrono::high_resolution_clock::now();

                (void)mst;
                double elapsed = chrono::duration<double>(end - start).count();
                allTimes[1][si].push_back(elapsed);
            }

            // --- Variacion 2: Heap + Optimized ---
            {
                UnionFind uf(n);
                vector<Edge> edgesCopy = edges;

                auto start = chrono::high_resolution_clock::now();
                vector<Edge> mst = kruskalHeapOptimized(edgesCopy, uf, n);
                auto end = chrono::high_resolution_clock::now();

                (void)mst;
                double elapsed = chrono::duration<double>(end - start).count();
                allTimes[2][si].push_back(elapsed);
            }

            // --- Variacion 3: Heap + No Optimize ---
            {
                UnionFind uf(n);
                vector<Edge> edgesCopy = edges;

                auto start = chrono::high_resolution_clock::now();
                vector<Edge> mst = kruskalHeapNoOptimize(edgesCopy, uf, n);
                auto end = chrono::high_resolution_clock::now();

                (void)mst;
                double elapsed = chrono::duration<double>(end - start).count();
                allTimes[3][si].push_back(elapsed);
            }
        }
    }

    // Mostrar resultados en consola
    cout << endl;
    cout << "=== RESULTADOS ===" << endl;
    cout << "Tiempos promedio (en segundos) sobre 5 repeticiones:" << endl << endl;

    // Cabecera de la tabla
    cout << left << setw(10) << "N";
    cout << setw(22) << "Sorted+Opt";
    cout << setw(22) << "Sorted+NoOpt";
    cout << setw(22) << "Heap+Opt";
    cout << setw(22) << "Heap+NoOpt";
    cout << endl;
    cout << string(100, '-') << endl;

    // Datos de cada tamano
    for (size_t si = 0; si < sizes.size(); si++) {
        int n = sizes[si];
        cout << left << setw(10) << n;

        for (int v = 0; v < 4; v++) {
            double sum = 0;
            for (double t : allTimes[v][si]) {
                sum += t;
            }
            double avg = sum / allTimes[v][si].size();
            cout << setw(22) << avg;
        }
        cout << endl;
    }

    // Guardar promedios en CSV
    {
        ofstream csv("resultados.csv");
        csv << "N,Sorted+Opt,Sorted+NoOpt,Heap+Opt,Heap+NoOpt" << endl;
        for (size_t si = 0; si < sizes.size(); si++) {
            int n = sizes[si];
            csv << n;
            for (int v = 0; v < 4; v++) {
                double sum = 0;
                for (double t : allTimes[v][si]) {
                    sum += t;
                }
                double avg = sum / allTimes[v][si].size();
                csv << "," << avg;
            }
            csv << endl;
        }
        csv.close();
        cout << endl << "Resultados promedio guardados en 'resultados.csv'" << endl;
    }

    // Guardar detalle (cada repeticion individual)
    {
        ofstream csvDet("resultados_detalle.csv");
        csvDet << "N,Repeticion,Sorted+Opt,Sorted+NoOpt,Heap+Opt,Heap+NoOpt" << endl;
        for (size_t si = 0; si < sizes.size(); si++) {
            int n = sizes[si];
            for (int rep = 0; rep < 5; rep++) {
                csvDet << n << "," << (rep + 1);
                for (int v = 0; v < 4; v++) {
                    csvDet << "," << allTimes[v][si][rep];
                }
                csvDet << endl;
            }
        }
        csvDet.close();
        cout << "Resultados detallados guardados en 'resultados_detalle.csv'" << endl;
    }

    return 0;
}
